/**
 * Get all available roles
 */
export function getAllRoles() {
    return Object.values(AGENT_PROFILES).map(profile => profile.role);
}

/**
 * Get agent by role
 */
export function getAgentByRole(role) {
    return Object.values(AGENT_PROFILES).find(profile => profile.role === role);
}

/**
 * Get agent by name
 */
export function getAgentByName(name) {
    return AGENT_PROFILES[name];
}

/**
 * List all agents with their roles
 */
export function listAgents() {
    return Object.entries(AGENT_PROFILES).map(([name, profile]) => ({
        name,
        role: profile.role,
        title: profile.title
    }));
}

/**
 * Build agent prompt with personality context
 */
export function buildAgentPrompt(agentName, task, basePrompt) {
    const agent = AGENT_PROFILES[agentName];
    if (!agent) {
        return basePrompt;
    }
    const agentContext = `
You are ${agent.name}, a ${agent.title}.
**Your Personality**: ${agent.personality}
**Your Specializations**: ${agent.specializations.join(', ')}

**Task**: ${task}

${basePrompt}

Remember to stay in character as ${agent.name} and apply your expertise to this task.
${agent.catchphrase}
`;
    return agentContext;
}
